import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getTasks, createTask, deleteTask, updateTask } from "../services/TaskService";
import { getCategories } from "../services/CategoryService";
import TaskForm from "../components/TaskForm";
import TaskList from "../components/TaskList";
import CategoryManager from "../components/CategoryManager";
import styles from "../styles/HomePage.module.css";

const HomePage = () => {
  const [user, setUser] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [categories, setCategories] = useState([]);
  const [editingTask, setEditingTask] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [filterPriority, setFilterPriority] = useState("");
  const [filterStatus, setFilterStatus] = useState("");
  const [message, setMessage] = useState({ type: "", text: "" });
  const navigate = useNavigate();

  useEffect(() => {
    const savedUser = localStorage.getItem("loggedUser");
    const token = localStorage.getItem("token");
    if (savedUser && token) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchUserTasks(parsedUser.id);
      loadInitialCategories();
    } else {
      navigate("/login");
    }
  }, [navigate]);

  const loadInitialCategories = async () => {
    try {
      const cats = await getCategories();
      setCategories(cats);
    } catch (e) {}
  };

  const showMessage = (type, text) => {
    setMessage({ type, text });
    setTimeout(() => setMessage({ type: "", text: "" }), 4000);
  };

  const fetchUserTasks = async (userId) => {
    try {
      const data = await getTasks(userId);
      setTasks(data);
    } catch (err) {
      showMessage("error", "Error al cargar las tareas.");
    }
  };

  const handleCreateTask = async (taskData) => {
    const newTask = await createTask(taskData, user.id);
    setTasks([...tasks, newTask]);
    setIsFormOpen(false);
    showMessage("success", "Tarea creada correctamente.");
  };

  const handleUpdateTask = async (taskId, updatedData) => {
    const updatedTask = await updateTask(taskId, updatedData);
    setTasks(tasks.map(t => t.id === taskId ? updatedTask : t));
    setEditingTask(null);
    setIsFormOpen(false);
    showMessage("success", "Tarea actualizada.");
  };

  const handleDeleteTask = async (taskId) => {
    try {
      await deleteTask(taskId);
      setTasks(tasks.filter((t) => t.id !== taskId));
    } catch (err) {
      showMessage("error", "Error al borrar la tarea.");
    }
  };

  const handleToggleStatus = async (task) => {
    try {
      const newStatus = task.status === "COMPLETADA" ? "PENDIENTE" : "COMPLETADA";
      const updatedTask = await updateTask(task.id, { ...task, status: newStatus });
      setTasks(tasks.map(t => t.id === task.id ? updatedTask : t));
    } catch (err) {
      showMessage("error", "Error al cambiar el estado.");
    }
  };

  const filteredTasks = tasks.filter((task) => {
    let matchPriority = true;
    let matchStatus = true;
    if (filterPriority) matchPriority = task.priority === filterPriority;
    if (filterStatus) matchStatus = task.status === filterStatus;
    return matchPriority && matchStatus;
  });

  const scheduledCount = tasks.filter(t => t.deadline).length;
  const highPriorityCount = tasks.filter(t => t.priority === "ALTA").length;
  const completedCount = tasks.filter(t => t.status === "COMPLETADA").length;

  if (!user) return <div style={{textAlign:"center", marginTop:"50px"}}>Cargando...</div>;
  const isGestorOrAdmin = user.role === "GESTOR" || user.role === "ADMIN" || user.roles?.includes("GESTOR");

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1 className={styles.title}>Mis Listas</h1>
        <button
          onClick={() => {
            localStorage.removeItem("loggedUser");
            localStorage.removeItem("token");
            navigate("/login");
          }}
          className={styles.logoutBtn}
        >
          Cerrar Sesión
        </button>
      </header>

      {message.text && (
        <div className={`${styles.message} ${message.type === "error" ? styles.msgError : styles.msgSuccess}`}>
          {message.type === "error" ? "❌ " : "✅ "} {message.text}
        </div>
      )}

      {/* Dashboard Estilo iOS */}
      <div className={styles.dashboardGrid}>
        <div className={`${styles.dashCard} ${styles.cardBlue}`} onClick={() => {setFilterStatus("PENDIENTE"); setFilterPriority("")}}>
          <span className={styles.dashCardIcon}>📅</span>
          <span className={styles.dashCardTitle}>Hoy / Pendientes</span>
          <span className={styles.dashCardCount}>{tasks.length - completedCount}</span>
        </div>
        <div className={`${styles.dashCard} ${styles.cardRed}`} onClick={() => setFilterPriority("ALTA")}>
          <span className={styles.dashCardIcon}>⏰</span>
          <span className={styles.dashCardTitle}>Urgentes</span>
          <span className={styles.dashCardCount}>{highPriorityCount}</span>
        </div>
        <div className={`${styles.dashCard} ${styles.cardGray}`} onClick={() => {setFilterStatus(""); setFilterPriority("")}}>
          <span className={styles.dashCardIcon}>🗂️</span>
          <span className={styles.dashCardTitle}>Todos</span>
          <span className={styles.dashCardCount}>{tasks.length}</span>
        </div>
        <div className={`${styles.dashCard} ${styles.cardOrange}`} onClick={() => setFilterStatus("COMPLETADA")}>
          <span className={styles.dashCardIcon}>✓</span>
          <span className={styles.dashCardTitle}>Completados</span>
          <span className={styles.dashCardCount}>{completedCount}</span>
        </div>
      </div>

      {isGestorOrAdmin && (
        <CategoryManager onCategoriesChange={(newCats) => setCategories(newCats)} />
      )}

      <h2 className={styles.sectionTitle}>Tareas</h2>

      <div className={styles.filters}>
        <select className={styles.filterSelect} value={filterPriority} onChange={e => setFilterPriority(e.target.value)}>
          <option value="">Prioridad (Todas)</option>
          <option value="ALTA">Alta</option>
          <option value="MEDIA">Media</option>
          <option value="BAJA">Baja</option>
        </select>
        <select className={styles.filterSelect} value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
          <option value="">Estado (Todos)</option>
          <option value="PENDIENTE">Pendientes</option>
          <option value="COMPLETADA">Completadas</option>
        </select>
      </div>

      <div className={styles.listContainer}>
        <TaskList 
          tasks={filteredTasks} 
          onDelete={handleDeleteTask} 
          onEdit={(task) => {
            setEditingTask(task);
            setIsFormOpen(true);
          }}
          onToggleStatus={handleToggleStatus}
        />
      </div>

      <button className={styles.fab} onClick={() => { setEditingTask(null); setIsFormOpen(true); }}>
        +
      </button>

      {isFormOpen && (
        <TaskForm 
          onTaskCreated={handleCreateTask} 
          onTaskUpdated={handleUpdateTask}
          editingTask={editingTask}
          onCancelEdit={() => { setEditingTask(null); setIsFormOpen(false); }}
          categories={categories} 
        />
      )}
    </div>
  );
};

export default HomePage;
